const data = $input.first().json;
const tickers = data.tickers.split(',').map(function(t) { return t.trim(); }).filter(Boolean);

return tickers.map(function(ticker) {
  return {
    json: {
      ticker: ticker,
      investment_query: ticker + ' latest investor relations SEC filings earnings call transcript financial news risk factors catalysts',
      email_to: data.email_to,
      email_from: data.email_from,
      email_subject_prefix: data.email_subject_prefix
    }
  };
});

const items = $input.all();

const watchlist = items.map(function(item) {
  return {
    ticker: item.json.ticker || 'Unknown',
    sources: item.json.organic || item.json.results || item.json.data || []
  };
});

const first = items.length > 0 ? items[0].json : {};

return [
  {
    json: {
      report_date: new Date().toISOString().split('T')[0],
      watchlist: watchlist,
      email_to: first.email_to || 'user@example.com',
      email_from: first.email_from || 'user@example.com',
      email_subject_prefix: first.email_subject_prefix || 'Daily Investment Research Report'
    }
  }
];

const output = $json.output && $json.output[0] && $json.output[0].content && $json.output[0].content[0] && $json.output[0].content[0].text;
const markdown = output || $json.text || '';

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

let html = escapeHtml(markdown);

html = html
  .replace(/\*\*(.*?)\*\*/gim, '<strong>$1</strong>')
  .replace(/\[(.*?)\]\((.*?)\)/gim, '<a href="$2">$1</a>');

html = html
  .replace(/^#### (.*$)/gim, '<h4>$1</h4>')
  .replace(/^### (.*$)/gim, '<h3>$1</h3>')
  .replace(/^## (.*$)/gim, '<h2>$1</h2>')
  .replace(/^# (.*$)/gim, '<h1>$1</h1>')
  .replace(/^---$/gim, '<hr />');

html = html.replace(/((?:^|\n)\|.+\|\n\|[-:\s|]+\|\n(?:\|.+\|\n?)+)/g, function(tableBlock) {
  const rows = tableBlock.trim().split('\n');
  const headers = rows[0].split('|').slice(1, -1).map(function(h) { return h.trim(); });
  const bodyRows = rows.slice(2).map(function(row) {
    return row.split('|').slice(1, -1).map(function(c) { return c.trim(); });
  });
  const thead = '<thead><tr>' + headers.map(function(h) { return '<th>' + h + '</th>'; }).join('') + '</tr></thead>';
  const tbody = '<tbody>' + bodyRows.map(function(cols) {
    return '<tr>' + cols.map(function(c) { return '<td>' + c + '</td>'; }).join('') + '</tr>';
  }).join('') + '</tbody>';
  return '<table>' + thead + tbody + '</table>';
});

html = html.replace(/(?:^|\n)(- .*(?:\n- .*)*)/g, function(match) {
  const items = match
    .trim()
    .split('\n')
    .map(function(line) { return '<li>' + line.replace(/^- /, '') + '</li>'; })
    .join('');
  return '<ul>' + items + '</ul>';
});

html = html
  .split('\n')
  .map(function(line) {
    const trimmed = line.trim();
    if (!trimmed) return '';
    if (
      trimmed.startsWith('<h') ||
      trimmed.startsWith('<ul') ||
      trimmed.startsWith('<li') ||
      trimmed.startsWith('</ul') ||
      trimmed.startsWith('<hr') ||
      trimmed.startsWith('<table') ||
      trimmed.startsWith('<thead') ||
      trimmed.startsWith('<tbody') ||
      trimmed.startsWith('<tr') ||
      trimmed.startsWith('<th') ||
      trimmed.startsWith('<td') ||
      trimmed.startsWith('</table')
    ) {
      return trimmed;
    }
    return '<p>' + trimmed + '</p>';
  })
  .join('\n');

const reportDate = new Date().toISOString().split('T')[0];
const subjectPrefix = $json.email_subject_prefix || 'Daily Investment Research Report';

let emailHtml = '<!doctype html>';
emailHtml += '<html><head><meta charset="utf-8"></head>';
emailHtml += '<body style="margin:0; padding:0; background:#f3f4f6; font-family:Arial, Helvetica, sans-serif; color:#111827;">';
emailHtml += '<div style="max-width:820px; margin:0 auto; padding:24px 14px;">';
emailHtml += '<div style="background:#ffffff; border:1px solid #e5e7eb; border-radius:12px; overflow:hidden;">';
emailHtml += '<div style="padding:22px 24px; border-bottom:3px solid #111827;">';
emailHtml += '<div style="font-size:11px; letter-spacing:0.12em; text-transform:uppercase; color:#6b7280; margin-bottom:8px;">Automated Investment Research</div>';
emailHtml += '<h1 style="font-size:26px; line-height:1.2; margin:0 0 6px 0; color:#0f172a;">Daily Investment Research Report</h1>';
emailHtml += '<div style="font-size:12px; color:#6b7280;">Generated on ' + reportDate + '</div>';
emailHtml += '</div>';
emailHtml += '<div style="padding:16px 24px; background:#f8fafc; border-bottom:1px solid #e5e7eb; font-size:13px; color:#374151;">';
emailHtml += 'This automated email summarizes opportunity signals, risk signals, and research priorities from public sources. It is not financial advice and does not provide buy, sell, or hold recommendations.';
emailHtml += '</div>';
emailHtml += '<div class="report-content" style="padding:8px 24px 24px 24px; font-size:14px; line-height:1.55;">' + html + '</div>';
emailHtml += '</div></div></body></html>';

const styledHtml = emailHtml
  .replace(/<h1>/g, '<h1 style="font-size:24px; line-height:1.2; margin:18px 0 8px; color:#0f172a;">')
  .replace(/<h2>/g, '<h2 style="font-size:18px; margin:24px 0 10px; padding-bottom:6px; border-bottom:1px solid #e5e7eb; color:#111827;">')
  .replace(/<h3>/g, '<h3 style="font-size:16px; margin:22px 0 10px; padding:10px 12px; border-left:4px solid #111827; background:#f9fafb; color:#111827;">')
  .replace(/<h4>/g, '<h4 style="font-size:12px; margin:16px 0 8px; color:#374151; text-transform:uppercase; letter-spacing:0.05em;">')
  .replace(/<p>/g, '<p style="margin:7px 0;">')
  .replace(/<ul>/g, '<ul style="margin:8px 0 14px 20px; padding:0;">')
  .replace(/<li>/g, '<li style="margin:4px 0;">')
  .replace(/<a /g, '<a style="color:#1d4ed8; text-decoration:none; word-break:break-word;" ')
  .replace(/<hr \/>/g, '<hr style="border:0; border-top:1px solid #d1d5db; margin:24px 0;" />')
  .replace(/<table>/g, '<table style="width:100%; border-collapse:collapse; margin:12px 0 18px; font-size:13px;">')
  .replace(/<th>/g, '<th style="border:1px solid #e5e7eb; padding:8px; text-align:left; background:#f9fafb;">')
  .replace(/<td>/g, '<td style="border:1px solid #e5e7eb; padding:8px; vertical-align:top;">');

return [
  {
    json: {
      email_to: $('Split Tickers').first().json.email_to,
      email_from: $('Split Tickers').first().json.email_from,
      email_subject: subjectPrefix + ' - ' + reportDate,
      email_html: styledHtml
    }
  }
];
